import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Layout, Typography, Avatar, Dropdown, Button, Menu, Grid, Drawer } from 'antd';
import {
  UserOutlined,
  LogoutOutlined,
  BellOutlined,
  SearchOutlined,
  MenuFoldOutlined,
  MenuUnfoldOutlined,
  FileTextOutlined,
  TeamOutlined,
  SettingOutlined,
  AuditOutlined,
  ToolOutlined,
  SafetyOutlined,
  HomeOutlined
} from '@ant-design/icons';
import CustomerForm from './pages/CustomerForm';
import BranchStaff from './pages/BranchStaff';
import CMD from './pages/CMD';
import Audit from './pages/Audit';
import WorkUnit from './pages/WorkUnit';
import ServiceQuality from './pages/ServiceQuality';
import { BRAND_COLORS } from './constants/theme';
import './index.css';

const { Header: AntHeader, Sider, Content } = Layout;
const { Title, Text } = Typography;

function SidebarMenu({ collapsed }) {
  const location = useLocation();

  const menuItems = [
    {
      key: '/',
      icon: <HomeOutlined />,
      label: <Link to="/">Customer Form</Link>,
    },
    {
      key: '/branch-staff',
      icon: <TeamOutlined />,
      label: <Link to="/branch-staff">Branch Staff</Link>,
    },
    {
      key: '/cmd',
      icon: <SettingOutlined />,
      label: <Link to="/cmd">CMD</Link>,
    },
    {
      key: '/audit',
      icon: <AuditOutlined />,
      label: <Link to="/audit">Audit Team</Link>,
    },
    {
      key: '/work-unit',
      icon: <ToolOutlined />,
      label: <Link to="/work-unit">Work Unit</Link>,
    },
    {
      key: '/service-quality',
      icon: <SafetyOutlined />,
      label: <Link to="/service-quality">Service Quality</Link>,
    },
  ];

  return (
    <Menu
      mode="inline"
      selectedKeys={[location.pathname]}
      items={menuItems}
      style={{ borderRight: 'none', padding: '0 8px' }}
    />
  );
}

function AppHeader({ collapsed, setCollapsed }) {
  const userMenu = {
    items: [
      {
        key: 'profile',
        label: 'My Profile',
        icon: <UserOutlined />,
      },
      {
        key: 'logout',
        label: 'Logout',
        icon: <LogoutOutlined />,
        danger: true,
      },
    ],
  };

  return (
    <AntHeader style={{
      padding: '0 24px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      zIndex: 10,
      boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
      height: '64px',
      backgroundColor: BRAND_COLORS.primary
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
        <Button
          type="text"
          icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
          onClick={() => setCollapsed(!collapsed)}
          style={{
            fontSize: '18px',
            color: 'white',
            display: 'none',
            padding: 0,
            width: 32,
            height: 32
          }}
          className="sidebar-toggle"
        />
        <img
          src="/download.png"
          alt="Dashen Bank Logo"
          style={{ height: '32px', width: 'auto', objectFit: 'contain' }}
        />
        <Title level={4} style={{ color: BRAND_COLORS.white, margin: 0, letterSpacing: '0.5px', whiteSpace: 'nowrap' }}>
          Complaint Management <span style={{ fontWeight: 400, opacity: 0.85, fontSize: '15px' }} className="hide-on-mobile">| System</span>
        </Title>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
        <div style={{
          borderRadius: '4px',
          backgroundColor: 'rgba(255,255,255,0.1)',
          border: '1px solid rgba(255,255,255,0.2)',
          color: 'white',
          width: '280px',
          display: 'flex',
          alignItems: 'center',
          padding: '0 12px',
          height: '32px'
        }} className="header-search hide-on-mobile">
          <SearchOutlined style={{ color: 'rgba(255,255,255,0.6)', marginRight: '8px' }} />
          <input
            placeholder="Search..."
            style={{
              backgroundColor: 'transparent',
              border: 'none',
              color: 'white',
              outline: 'none',
              width: '100%',
              fontSize: '14px'
            }}
          />
        </div>
        <BellOutlined style={{ fontSize: '18px', cursor: 'pointer', color: BRAND_COLORS.white }} />
        <Dropdown menu={userMenu} trigger={['click']}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}>
            <Avatar style={{ backgroundColor: BRAND_COLORS.accent, color: BRAND_COLORS.primary, fontWeight: 'bold' }}>A</Avatar>
            <div style={{ display: 'flex', flexDirection: 'column', lineHeight: '1.2' }} className="hide-on-mobile">
              <Text style={{ color: BRAND_COLORS.white, fontWeight: 500 }}>Admin User</Text>
              <Text style={{ color: 'rgba(255,255,255,0.7)', fontSize: '12px' }}>System Admin</Text>
            </div>
          </div>
        </Dropdown>
      </div>
    </AntHeader>
  );
}

function App() {
  const [collapsed, setCollapsed] = useState(false);
  const [mobileDrawerOpen, setMobileDrawerOpen] = useState(false);
  const screens = Grid.useBreakpoint();
  const isMobile = !screens.lg;

  return (
    <Router>
      <Layout style={{ height: '100vh', width: '100vw', overflow: 'hidden' }}>
        <AppHeader collapsed={collapsed} setCollapsed={setCollapsed} />
        <Layout style={{ overflow: 'hidden' }}>
          {/* Desktop Sidebar */}
          {!isMobile && (
            <Sider
              trigger={null}
              collapsible
              collapsed={collapsed}
              width={260}
              theme="light"
              style={{
                borderRight: `1px solid ${BRAND_COLORS.sidebarBorder}`,
                boxShadow: '2px 0 8px rgba(0,0,0,0.02)',
                zIndex: 5,
                height: 'calc(100vh - 64px)',
                position: 'relative'
              }}
            >
              <div style={{ padding: '16px', display: 'flex', justifyContent: collapsed ? 'center' : 'flex-end' }}>
                <Button
                  type="text"
                  icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
                  onClick={() => setCollapsed(!collapsed)}
                  style={{ fontSize: '16px' }}
                />
              </div>
              <SidebarMenu collapsed={collapsed} />
            </Sider>
          )}

          {/* Mobile Sidebar */}
          <Drawer
            title="Complaint Management"
            placement="left"
            onClose={() => setMobileDrawerOpen(false)}
            open={isMobile && mobileDrawerOpen}
            width={280}
            styles={{ body: { padding: 0 } }}
          >
            <SidebarMenu collapsed={false} />
          </Drawer>

          <Layout style={{ display: 'flex', flexDirection: 'column' }}>
            <Content
              className="main-content-area"
              style={{
                background: BRAND_COLORS.background,
                overflowY: 'auto',
                flex: '1 1 auto',
              }}
            >
              <Routes>
                <Route path="/" element={<CustomerForm />} />
                <Route path="/branch-staff" element={<BranchStaff />} />
                <Route path="/cmd" element={<CMD />} />
                <Route path="/audit" element={<Audit />} />
                <Route path="/work-unit" element={<WorkUnit />} />
                <Route path="/service-quality" element={<ServiceQuality />} />
              </Routes>
            </Content>
          </Layout>
        </Layout>
      </Layout>
    </Router>
  );
}

export default App;
